+fn expected_policy_action_for_class(class_name: &str) -> &'static str {
+    match class_name {
+        "containment_trigger" => "challenge_and_contain",
+        "fault_containment" => "quarantine",
+        "degraded_mode_recovery" => "degraded_mode",
+        _ => "unknown",
+    }
